package main.rice.obj;

import java.util.StringJoiner;

public abstract class AIterablePyObj<T> extends APyObj<T> {
    protected AIterablePyObj(T value) {
        super(value);
    }

    protected String joinElements(Iterable<?> iterable) {
        StringJoiner joiner = new StringJoiner(", ");
        for (Object item : iterable) {
            joiner.add(String.valueOf(item));
        }
        return joiner.toString();
    }
}

package main.rice.obj;

import java.util.Objects;

public abstract class APyObj<T> {
    private final T value;

    protected APyObj(T value) {
        this.value = value;
    }

    public T getValue() {
        return value;
    }

    @Override
    public abstract String toString();

    @Override
    public boolean equals(Object other) {
        if (this == other) {
            return true;
        }
        if (other == null || getClass() != other.getClass()) {
            return false;
        }
        APyObj<?> pyObj = (APyObj<?>) other;
        return Objects.equals(value, pyObj.value);
    }

    @Override
    public int hashCode() {
        return Objects.hash(getClass(), value);
    }
}

package main.rice.obj;

public class PyBoolObj extends APyObj<Boolean> {
    public PyBoolObj(boolean value) {
        super(value);
    }

    @Override
    public String toString() {
        return getValue() ? "True" : "False";
    }
}

package main.rice.obj;

public class PyCharObj extends APyObj<Character> {
    public PyCharObj(char value) {
        super(value);
    }

    @Override
    public String toString() {
        return "'" + getValue() + "'";
    }
}

package main.rice.obj;

import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.StringJoiner;

public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends APyObj<Map<K, V>> {
    public PyDictObj(Map<K, V> value) {
        super(Collections.unmodifiableMap(new LinkedHashMap<>(value)));
    }

    @Override
    public Map<K, V> getValue() {
        return super.getValue();
    }

    @Override
    public String toString() {
        StringJoiner joiner = new StringJoiner(", ");
        for (Map.Entry<K, V> entry : getValue().entrySet()) {
            joiner.add(entry.getKey() + ": " + entry.getValue());
        }
        return "{" + joiner + "}";
    }
}

