package main.rice.obj;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class PyListObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {
    public PyListObj(List<T> value) {
        super(Collections.unmodifiableList(new ArrayList<>(value)));
    }

    @Override
    public List<T> getValue() {
        return super.getValue();
    }

    @Override
    public String toString() {
        return "[" + joinElements(getValue()) + "]";
    }
}

package main.rice.obj;

import java.util.Collections;
import java.util.LinkedHashSet;
import java.util.Set;

public class PySetObj<T extends APyObj<?>> extends AIterablePyObj<Set<T>> {
    public PySetObj(Set<T> value) {
        super(Collections.unmodifiableSet(new LinkedHashSet<>(value)));
    }

    @Override
    public Set<T> getValue() {
        return super.getValue();
    }

    @Override
    public String toString() {
        if (getValue().isEmpty()) {
            return "set()";
        }
        return "{" + joinElements(getValue()) + "}";
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {
    private final String rawValue;

    public PyStringObj(String value) {
        super(toPyChars(value));
        this.rawValue = value;
    }

    @Override
    public List<PyCharObj> getValue() {
        return super.getValue();
    }

    @Override
    public String toString() {
        return "'" + rawValue + "'";
    }

    private static List<PyCharObj> toPyChars(String value) {
        List<PyCharObj> chars = new ArrayList<>();
        for (char c : value.toCharArray()) {
            chars.add(new PyCharObj(c));
        }
        return Collections.unmodifiableList(chars);
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class PyTupleObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {
    public PyTupleObj(List<T> value) {
        super(Collections.unmodifiableList(new ArrayList<>(value)));
    }

    @Override
    public List<T> getValue() {
        return super.getValue();
    }

    @Override
    public String toString() {
        if (getValue().isEmpty()) {
            return "()";
        }
        if (getValue().size() == 1) {
            return "(" + getValue().get(0) + ",)";
        }
        return "(" + joinElements(getValue()) + ")";
    }
}
